module RefModule(
  output reg [2:0] cycle,
  input clk,
  input enn
);reg [2:0] unused_register = 3'b000;

  always @(posedge clk) begin
    if(!enn)
      unused_register <= (unused_register == 3'b111) ? 3'b000 : unused_register + 1;
    else
      unused_register <= 3'b000;
  end

  assign cycle = unused_register;

endmodule
